  ChainId.POLYGON_AMOY,
  "0x1234567890123456789012345678901234567890"
);
if (escrow) {
  console.log('Escrow status:', escrow.status);
}
</code></pre>

Type Description <code>ErrorInvalidAddress</code> If the launcher address is invalid <code>ErrorUnsupportedChainID</code> If the chain ID is not supported Example <pre><code>import { ChainId, EscrowStatus } from '@human-protocol/sdk';

